import "@testing-library/jest-dom";
import React from "react";
import { render, screen, waitFor } from "@testing-library/react";

jest.mock("@/lib/api", () => ({
	__esModule: true,
	default: {
		get: jest.fn(),
	},
}));

jest.mock("lucide-react", () => ({
	ArrowUpRight: () => <svg data-testid="icon-arrow" />,
	DollarSign: () => <svg data-testid="icon-dollar" />,
	ShoppingBag: () => <svg data-testid="icon-bag" />,
	Users: () => <svg data-testid="icon-users" />,
}));

jest.mock("recharts", () => ({
	LineChart: ({ children }: any) => (
		<div data-testid="line-chart">{children}</div>
	),
	BarChart: ({ children }: any) => (
		<div data-testid="bar-chart">{children}</div>
	),
	PieChart: ({ children }: any) => (
		<div data-testid="pie-chart">{children}</div>
	),
	Pie: () => <div />,
	Cell: () => <span />,
	Line: () => <div />,
	Bar: () => <div />,
	XAxis: () => <div />,
	YAxis: () => <div />,
	CartesianGrid: () => <div />,
	Tooltip: () => <div />,
	Legend: () => <div />,
	ResponsiveContainer: ({ children }: any) => <div>{children}</div>,
}));

import api from "@/lib/api";
import Dashboard from "@/app/dashboard/page";

const mockApi = api as jest.Mocked<typeof api>;

const mockMetrics = {
	total_revenue: 125000.5,
	count_sales: 340,
	avg_check: 367.65,
	total_quantity: 1200,
};

const mockRevenueData = [
	{ d1: "January", d2: "2024", value: 15000 },
	{ d1: "February", d2: "2024", value: 18000 },
];

describe("Dashboard — успішне завантаження даних", () => {
	beforeEach(() => {
		mockApi.get.mockImplementation((url: string) => {
			if (url === "/dashboard/metrics") {
				return Promise.resolve({ data: mockMetrics });
			}
			if (url.includes("/reports/aggregate")) {
				return Promise.resolve({ data: mockRevenueData });
			}
			return Promise.resolve({ data: {} });
		});
	});

	afterEach(() => {
		jest.clearAllMocks();
	});

	it("спочатку показує індикатор завантаження", () => {
		render(<Dashboard />);
		expect(screen.getByText("Loading...")).toBeInTheDocument();
	});

	it("відображає заголовок Dashboard після завантаження", async () => {
		render(<Dashboard />);
		await waitFor(() => {
			expect(screen.getByText("Dashboard")).toBeInTheDocument();
		});
	});

	it("відображає картку Total Revenue з правильним значенням", async () => {
		render(<Dashboard />);
		await waitFor(() => {
			expect(screen.getByText("Total Revenue")).toBeInTheDocument();
			expect(screen.getByText("$125000.50")).toBeInTheDocument();
		});
	});

	it("відображає картку Total Sales з правильним значенням", async () => {
		render(<Dashboard />);
		await waitFor(() => {
			expect(screen.getByText("Total Sales")).toBeInTheDocument();
			expect(screen.getByText("340")).toBeInTheDocument();
		});
	});

	it("відображає картки Avg Check та Quantity Sold", async () => {
		render(<Dashboard />);
		await waitFor(() => {
			expect(screen.getByText("Avg Check")).toBeInTheDocument();
			expect(screen.getByText("Quantity Sold")).toBeInTheDocument();
		});
	});

	it("викликає обидва API-ендпоінти", async () => {
		render(<Dashboard />);
		await waitFor(() => {
			expect(mockApi.get).toHaveBeenCalledWith("/dashboard/metrics");
			expect(mockApi.get).toHaveBeenCalledWith(
				expect.stringContaining("/reports/aggregate"),
			);
		});
	});

	it("відображає секцію Revenue Trend після завантаження", async () => {
		render(<Dashboard />);
		await waitFor(() => {
			expect(screen.getByText("Revenue Trend")).toBeInTheDocument();
		});
	});
});

describe("Dashboard — помилка завантаження даних", () => {
	beforeEach(() => {
		jest.spyOn(console, "error").mockImplementation(() => {});
		mockApi.get.mockRejectedValue(new Error("Server error"));
	});

	afterEach(() => {
		jest.clearAllMocks();
		(console.error as jest.Mock).mockRestore();
	});

	it("не показує Loading... після помилки", async () => {
		render(<Dashboard />);
		await waitFor(() => {
			expect(screen.queryByText("Loading...")).not.toBeInTheDocument();
		});
	});

	it("не крашається при помилці API", async () => {
		expect(() => render(<Dashboard />)).not.toThrow();
		await waitFor(() => {
			expect(mockApi.get).toHaveBeenCalled();
		});
	});
});

import "@testing-library/jest-dom";
import React from "react";
import { render, screen, waitFor } from "@testing-library/react";

jest.mock("@/lib/api", () => ({
	__esModule: true,
	default: {
		get: jest.fn(),
	},
}));

jest.mock("lucide-react", () => ({
	Trophy: ({ className }: any) => (
		<svg data-testid="trophy-icon" className={className} />
	),
}));

import api from "@/lib/api";
import RankingsPage from "@/app/rankings/page";

const mockApi = api as jest.Mocked<typeof api>;

const mockManagers = [
	{ rank: 1, name: "Alice Johnson", revenue: 125000 },
	{ rank: 2, name: "Bob Smith", revenue: 98000 },
	{ rank: 3, name: "Carol Davis", revenue: 87500 },
];

const mockProducts = [
	{ rank: 1, name: "Widget Pro", revenue: 45000 },
	{ rank: 2, name: "Gadget X", revenue: 38000 },
];

const mockRegions = [
	{ rank: 1, name: "North Region", revenue: 210000 },
	{ rank: 2, name: "South Region", revenue: 175000 },
];

describe("RankingsPage — успішне завантаження даних", () => {
	beforeEach(() => {
		mockApi.get.mockImplementation((url: string) => {
			if (url === "/rankings/manager")
				return Promise.resolve({ data: mockManagers });
			if (url === "/rankings/product")
				return Promise.resolve({ data: mockProducts });
			if (url === "/rankings/region")
				return Promise.resolve({ data: mockRegions });
			return Promise.resolve({ data: [] });
		});
	});

	afterEach(() => jest.clearAllMocks());

	it("показує Loading... під час завантаження", () => {
		render(<RankingsPage />);
		expect(screen.getByText("Loading...")).toBeInTheDocument();
	});

	it("відображає заголовок Rankings після завантаження", async () => {
		render(<RankingsPage />);
		await waitFor(() => {
			expect(screen.getByText("Rankings")).toBeInTheDocument();
		});
	});

	it("відображає секцію Top Managers", async () => {
		render(<RankingsPage />);
		await waitFor(() => {
			expect(screen.getByText("Top Managers")).toBeInTheDocument();
		});
	});

	it("відображає секцію Top Products", async () => {
		render(<RankingsPage />);
		await waitFor(() => {
			expect(screen.getByText("Top Products")).toBeInTheDocument();
		});
	});

	it("відображає секцію Top Regions", async () => {
		render(<RankingsPage />);
		await waitFor(() => {
			expect(screen.getByText("Top Regions")).toBeInTheDocument();
		});
	});

	it("відображає імена менеджерів", async () => {
		render(<RankingsPage />);
		await waitFor(() => {
			expect(screen.getByText("Alice Johnson")).toBeInTheDocument();
			expect(screen.getByText("Bob Smith")).toBeInTheDocument();
			expect(screen.getByText("Carol Davis")).toBeInTheDocument();
		});
	});

	it("відображає назви продуктів", async () => {
		render(<RankingsPage />);
		await waitFor(() => {
			expect(screen.getByText("Widget Pro")).toBeInTheDocument();
			expect(screen.getByText("Gadget X")).toBeInTheDocument();
		});
	});

	it("відображає назви регіонів", async () => {
		render(<RankingsPage />);
		await waitFor(() => {
			expect(screen.getByText("North Region")).toBeInTheDocument();
			expect(screen.getByText("South Region")).toBeInTheDocument();
		});
	});

	it("відображає revenue менеджерів у форматі з $", async () => {
		render(<RankingsPage />);
		await waitFor(() => {
			const revenueEl = screen.getByText(/\$125/);
			expect(revenueEl).toBeInTheDocument();
		});
	});

	it("відображає ранги у списку (1, 2, 3...)", async () => {
		render(<RankingsPage />);
		await waitFor(() => {
			const rankBadges = screen.getAllByText("1");
			expect(rankBadges.length).toBeGreaterThanOrEqual(3);
		});
	});

	it("рендерить 3 Trophy іконки (по одній на секцію)", async () => {
		render(<RankingsPage />);
		await waitFor(() => {
			const trophies = screen.getAllByTestId("trophy-icon");
			expect(trophies).toHaveLength(3);
		});
	});

	it("викликає всі три rankings ендпоінти", async () => {
		render(<RankingsPage />);
		await waitFor(() => {
			expect(mockApi.get).toHaveBeenCalledWith("/rankings/manager");
			expect(mockApi.get).toHaveBeenCalledWith("/rankings/product");
			expect(mockApi.get).toHaveBeenCalledWith("/rankings/region");
		});
	});
});

describe("RankingsPage — помилка завантаження", () => {
	beforeEach(() => {
		mockApi.get.mockRejectedValue(new Error("API unavailable"));
		jest.spyOn(console, "error").mockImplementation(() => {});
	});

	afterEach(() => {
		jest.clearAllMocks();
		(console.error as jest.Mock).mockRestore();
	});

	it("не показує Loading... після помилки", async () => {
		render(<RankingsPage />);
		await waitFor(() => {
			expect(screen.queryByText("Loading...")).not.toBeInTheDocument();
		});
	});

	it("рендериться без краша при помилці API", async () => {
		expect(() => render(<RankingsPage />)).not.toThrow();
		await waitFor(() => {
			expect(mockApi.get).toHaveBeenCalled();
		});
	});

	it("відображає заголовок Rankings навіть при помилці (порожні дані)", async () => {
		render(<RankingsPage />);
		await waitFor(() => {
			expect(screen.getByText("Rankings")).toBeInTheDocument();
		});
	});
});

import "@testing-library/jest-dom";
import React from "react";
import { render, screen, fireEvent, waitFor } from "@testing-library/react";

jest.mock("@/lib/api", () => ({
	__esModule: true,
	default: {
		get: jest.fn(),
		post: jest.fn(),
		put: jest.fn(),
		delete: jest.fn(),
	},
}));

jest.mock("lucide-react", () => ({
	Plus: () => <svg />,
	Edit: () => <svg />,
	Trash2: ({ className }: any) => (
		<svg data-testid="trash-icon" className={className} />
	),
	X: () => <svg />,
	Search: () => <svg data-testid="search-icon" />,
}));

import api from "@/lib/api";
import SalesPage from "@/app/sales/page";

const mockApi = api as jest.Mocked<typeof api>;

const mockSales = [
	{
		id: 1,
		sale_id: 1001,
		date: "2024-01-15",
		product_id: 10,
		manager_id: 5,
		region_id: 3,
		quantity: 2,
		unit_price: 299.99,
		discount: 0,
		revenue: 599.98,
		payment_type: "card",
		sales_channel: "store",
		supplier_id: 7,
	},
	{
		id: 2,
		sale_id: 1002,
		date: "2024-01-16",
		product_id: 11,
		manager_id: 6,
		region_id: 4,
		quantity: 1,
		unit_price: 149.99,
		discount: 10,
		revenue: 134.99,
		payment_type: "online",
		sales_channel: "online_store",
		supplier_id: 8,
	},
];

const mockDims = {
	products: [
		{ id: 10, name: "Widget Pro" },
		{ id: 11, name: "Gadget X" },
	],
	managers: [
		{ id: 5, name: "Alice Johnson" },
		{ id: 6, name: "Bob Smith" },
	],
	regions: [
		{ id: 3, name: "North Region" },
		{ id: 4, name: "South Region" },
	],
	suppliers: [
		{ id: 7, name: "Supplier A" },
		{ id: 8, name: "Supplier B" },
	],
};

const setupSuccessMocks = () => {
	mockApi.get.mockImplementation((url: string, config?: any) => {
		if (url === "/sales") return Promise.resolve({ data: mockSales });
		if (url === "/sales/count") return Promise.resolve({ data: { count: 2 } });
		if (url === "/dims/product")
			return Promise.resolve({ data: mockDims.products });
		if (url === "/dims/manager")
			return Promise.resolve({ data: mockDims.managers });
		if (url === "/dims/region")
			return Promise.resolve({ data: mockDims.regions });
		if (url === "/dims/supplier")
			return Promise.resolve({ data: mockDims.suppliers });
		return Promise.resolve({ data: [] });
	});
};

describe("SalesPage — завантаження та відображення даних", () => {
	beforeEach(() => {
		setupSuccessMocks();
	});

	afterEach(() => jest.clearAllMocks());

	it("показує Loading... під час завантаження", () => {
		render(<SalesPage />);
		expect(screen.getByText("Loading...")).toBeInTheDocument();
	});

	it("відображає заголовок Sales Management після завантаження", async () => {
		render(<SalesPage />);
		await waitFor(() => {
			expect(screen.getByText("Sales Management")).toBeInTheDocument();
		});
	});

	it("відображає рядки таблиці з датами продажів", async () => {
		render(<SalesPage />);
		await waitFor(() => {
			expect(screen.getByText("2024-01-15")).toBeInTheDocument();
			expect(screen.getByText("2024-01-16")).toBeInTheDocument();
		});
	});

	it("відображає назви продуктів з dims", async () => {
		render(<SalesPage />);
		await waitFor(() => {
			expect(screen.getByText("Widget Pro")).toBeInTheDocument();
			expect(screen.getByText("Gadget X")).toBeInTheDocument();
		});
	});

	it("відображає ім'я менеджера з dims", async () => {
		render(<SalesPage />);
		await waitFor(() => {
			expect(screen.getByText("Alice Johnson")).toBeInTheDocument();
		});
	});

	it("відображає revenue із знаком $", async () => {
		render(<SalesPage />);
		await waitFor(() => {
			expect(screen.getByText("$599.98")).toBeInTheDocument();
		});
	});

	it("відображає пагінацію: кнопки Previous та Next", async () => {
		render(<SalesPage />);
		await waitFor(() => {
			expect(screen.getByText("Previous")).toBeInTheDocument();
			expect(screen.getByText("Next")).toBeInTheDocument();
		});
	});

	it("показує поточну сторінку", async () => {
		render(<SalesPage />);
		await waitFor(() => {
			expect(screen.getByText(/Page 1 of/)).toBeInTheDocument();
		});
	});
});

describe("SalesPage — видалення продажу", () => {
	beforeEach(() => {
		setupSuccessMocks();
		mockApi.delete.mockResolvedValue({ data: {} });
	});

	afterEach(() => jest.clearAllMocks());

	it("не видаляє запис, якщо скасовано confirm", async () => {
		window.confirm = jest.fn(() => false);

		render(<SalesPage />);
		await waitFor(() => screen.getByText("2024-01-15"));

		const trashButtons = screen.getAllByTestId("trash-icon");
		fireEvent.click(trashButtons[0].closest("button")!);

		expect(mockApi.delete).not.toHaveBeenCalled();
	});

	it("викликає api.delete після підтвердження", async () => {
		window.confirm = jest.fn(() => true);

		render(<SalesPage />);
		await waitFor(() => screen.getByText("2024-01-15"));

		const trashButtons = screen.getAllByTestId("trash-icon");
		fireEvent.click(trashButtons[0].closest("button")!);

		await waitFor(() => {
			expect(mockApi.delete).toHaveBeenCalledWith("/sales/1");
		});
	});

	it("оновлює список продажів після видалення (викликає fetchSales знову)", async () => {
		window.confirm = jest.fn(() => true);

		render(<SalesPage />);
		await waitFor(() => screen.getByText("2024-01-15"));

		const callsBefore = mockApi.get.mock.calls.length;
		const trashButtons = screen.getAllByTestId("trash-icon");
		fireEvent.click(trashButtons[0].closest("button")!);

		await waitFor(() => {
			expect(mockApi.get.mock.calls.length).toBeGreaterThan(callsBefore);
		});
	});
});

describe("SalesPage — помилка при видаленні", () => {
	beforeEach(() => {
		setupSuccessMocks();
		mockApi.delete.mockRejectedValue(new Error("Delete failed"));
		window.confirm = jest.fn(() => true);
		jest.spyOn(console, "error").mockImplementation(() => {});
	});

	afterEach(() => {
		jest.clearAllMocks();
		(console.error as jest.Mock).mockRestore();
	});

	it("не крашається при помилці видалення", async () => {
		render(<SalesPage />);
		await waitFor(() => screen.getByText("2024-01-15"));

		const trashButtons = screen.getAllByTestId("trash-icon");
		expect(() =>
			fireEvent.click(trashButtons[0].closest("button")!),
		).not.toThrow();

		await waitFor(() => {
			expect(mockApi.delete).toHaveBeenCalled();
		});
	});
});

describe("SalesPage — пошук", () => {
	beforeEach(() => {
		setupSuccessMocks();
	});

	afterEach(() => jest.clearAllMocks());

	it("відображає поле пошуку", async () => {
		render(<SalesPage />);
		await waitFor(() => screen.getByText("Sales Management"));
		expect(
			screen.getByPlaceholderText(
				"Search by product, manager, region, or city...",
			),
		).toBeInTheDocument();
	});

	it("надсилає запит із searchTerm при кліку на Search", async () => {
		render(<SalesPage />);
		await waitFor(() => screen.getByText("Sales Management"));

		const searchInput = screen.getByPlaceholderText(
			"Search by product, manager, region, or city...",
		);
		fireEvent.change(searchInput, { target: { value: "Widget" } });
		fireEvent.click(screen.getByRole("button", { name: "Search" }));

		await waitFor(() => {
			const getCalls = mockApi.get.mock.calls;
			const salesCall = getCalls.find(
				([url, config]) =>
					url === "/sales" && config?.params?.search === "Widget",
			);
			expect(salesCall).toBeDefined();
		});
	});

	it("натискання Enter у полі пошуку запускає пошук", async () => {
		render(<SalesPage />);
		await waitFor(() => screen.getByText("Sales Management"));

		const searchInput = screen.getByPlaceholderText(
			"Search by product, manager, region, or city...",
		);
		fireEvent.change(searchInput, { target: { value: "Alice" } });
		fireEvent.keyDown(searchInput, { key: "Enter", code: "Enter" });

		await waitFor(() => {
			const getCalls = mockApi.get.mock.calls;
			const salesCall = getCalls.find(
				([url, config]) =>
					url === "/sales" && config?.params?.search === "Alice",
			);
			expect(salesCall).toBeDefined();
		});
	});
});

import "@testing-library/jest-dom";
import React from "react";
import { render, screen, fireEvent, waitFor } from "@testing-library/react";
import userEvent from "@testing-library/user-event";

jest.mock("@/lib/api", () => ({
	__esModule: true,
	default: {
		get: jest.fn(),
		post: jest.fn(),
	},
}));

jest.mock("lucide-react", () => ({
	Upload: () => <svg data-testid="icon-upload" />,
	FileSpreadsheet: () => <svg data-testid="icon-spreadsheet" />,
	CheckCircle: () => <svg data-testid="icon-check" />,
	AlertCircle: () => <svg data-testid="icon-alert" />,
}));

import api from "@/lib/api";
import UploadPage from "@/app/upload/page";

const mockApi = api as jest.Mocked<typeof api>;

const selectFile = (filename = "sales.xlsx", size = 1024) => {
	const file = new File(["col1,col2\nval1,val2"], filename, {
		type: "application/vnd.openxmlformats-officedocument.spreadsheetml.sheet",
	});
	Object.defineProperty(file, "size", { value: size });
	const input =
		(screen.getByRole("textbox", { hidden: true }) as HTMLInputElement) ||
		(document.querySelector('input[type="file"]') as HTMLInputElement);
	fireEvent.change(input, { target: { files: [file] } });
	return file;
};

describe("UploadPage — рендеринг початкового стану", () => {
	it("відображає заголовок Upload Sales Data", () => {
		render(<UploadPage />);
		expect(screen.getByText("Upload Sales Data")).toBeInTheDocument();
	});

	it("не показує кнопку Upload до вибору файлу", () => {
		render(<UploadPage />);
		expect(screen.queryByText("Upload")).not.toBeInTheDocument();
	});

	it("відображає список очікуваних стовпців", () => {
		render(<UploadPage />);
		expect(screen.getByText("Expected Columns")).toBeInTheDocument();
		expect(screen.getByText("sale_id")).toBeInTheDocument();
		expect(screen.getByText("quantity")).toBeInTheDocument();
	});

	it("відображає поле для вибору файлу (.xlsx)", () => {
		render(<UploadPage />);
		const input = document.querySelector('input[type="file"]');
		expect(input).toBeInTheDocument();
		expect(input).toHaveAttribute("accept", ".xlsx, .xls");
	});
});

describe("UploadPage — вибір файлу", () => {
	it("відображає ім'я файлу після вибору", () => {
		render(<UploadPage />);
		const input = document.querySelector(
			'input[type="file"]',
		) as HTMLInputElement;
		const file = new File(["data"], "sales_2024.xlsx", {
			type: "application/vnd.ms-excel",
		});
		fireEvent.change(input, { target: { files: [file] } });
		expect(screen.getByText("sales_2024.xlsx")).toBeInTheDocument();
	});

	it("відображає розмір файлу після вибору", () => {
		render(<UploadPage />);
		const input = document.querySelector(
			'input[type="file"]',
		) as HTMLInputElement;
		const file = new File(["x".repeat(2048)], "data.xlsx", {
			type: "application/vnd.ms-excel",
		});
		fireEvent.change(input, { target: { files: [file] } });
		expect(screen.getByText(/KB/)).toBeInTheDocument();
	});
});

describe("UploadPage — успішне завантаження файлу", () => {
	beforeEach(() => {
		mockApi.post.mockResolvedValue({
			data: { rows_inserted: 45, rows_processed: 50 },
		});
	});

	afterEach(() => jest.clearAllMocks());

	it("показує Success-повідомлення після завантаження", async () => {
		render(<UploadPage />);

		const input = document.querySelector(
			'input[type="file"]',
		) as HTMLInputElement;
		const file = new File(["data"], "sales.xlsx", {
			type: "application/vnd.ms-excel",
		});
		fireEvent.change(input, { target: { files: [file] } });

		const uploadBtn = screen.getByText("Upload").closest("button")!;
		fireEvent.click(uploadBtn);

		await waitFor(() => {
			expect(screen.getByText("Success")).toBeInTheDocument();
		});
		expect(
			screen.getByText(
				/Successfully processed 45 new records \(from 50 total\)/,
			),
		).toBeInTheDocument();
	});

	it("надсилає POST на /upload/sales з FormData", async () => {
		render(<UploadPage />);

		const input = document.querySelector(
			'input[type="file"]',
		) as HTMLInputElement;
		const file = new File(["data"], "sales.xlsx", {
			type: "application/vnd.ms-excel",
		});
		fireEvent.change(input, { target: { files: [file] } });

		fireEvent.click(screen.getByText("Upload").closest("button")!);

		await waitFor(() => {
			expect(mockApi.post).toHaveBeenCalledWith(
				"/upload/sales",
				expect.any(FormData),
				expect.objectContaining({
					headers: { "Content-Type": "multipart/form-data" },
				}),
			);
		});
	});

	it("очищує вибраний файл після успішного завантаження", async () => {
		render(<UploadPage />);

		const input = document.querySelector(
			'input[type="file"]',
		) as HTMLInputElement;
		const file = new File(["data"], "test.xlsx", {
			type: "application/vnd.ms-excel",
		});
		fireEvent.change(input, { target: { files: [file] } });

		fireEvent.click(screen.getByText("Upload").closest("button")!);

		await waitFor(() => {
			expect(screen.getByText("Success")).toBeInTheDocument();
		});
		expect(screen.queryByText("test.xlsx")).not.toBeInTheDocument();
	});
});

