										{[
											"China",
											"Germany",
											"Poland",
											"Romania",
											"Sweden",
											"Ukraine",
											"USA",
										].map((c) => (
											<option key={c} value={c}>
												{c}
											</option>
										))}
									</select>
								</div>

								{/* Quantity */}
								<div>
									<label className="block text-sm font-medium text-gray-700">
										Quantity
									</label>
									<input
										type="number"
