									/>
								</div>

								{/* Discount */}
								<div>
									<label className="block text-sm font-medium text-gray-700">
										Discount
									</label>
									<input
										type="number"
										step="0.01"
										{...register("discount")}
										defaultValue={0}
										className="mt-1 block w-full border rounded p-2 text-sm"
									/>
								</div>

								{/* Payment Type - dropdown */}
								<div>
									<label className="block text-sm font-medium text-gray-700">
										Payment Type
									</label>
									<select
										{...register("payment_type")}
										className="mt-1 block w-full border rounded p-2 text-sm"
									>
										<option value="">Select...</option>
										<option value="Cash">Cash</option>
										<option value="Card">Card</option>
										<option value="Online">Online</option>
										<option value="Installments">Installments</option>
									</select>
								</div>

								{/* Sales Channel - dropdown */}
								<div>
									<label className="block text-sm font-medium text-gray-700">
										Sales Channel
									</label>
									<select
										{...register("sales_channel")}
										className="mt-1 block w-full border rounded p-2 text-sm"
									>
										<option value="">Select...</option>
										<option value="Website">Website</option>
										<option value="Store">Store</option>
										<option value="Mobile App">Mobile App</option>
										<option value="Marketplace">Marketplace</option>
									</select>
								</div>
							</div>

							<div className="flex justify-end pt-4">
								<button
									type="button"
									onClick={() => setModalOpen(false)}
									className="mr-2 px-4 py-2 border rounded text-gray-600"
								>
									Cancel
								</button>
								<button
									type="submit"
									className="px-4 py-2 bg-blue-600 text-white rounded hover:bg-blue-700"
								>
									Save
								</button>
							</div>
						</form>
					</div>
				</div>
			)}
		</div>
	);
}

"use client";

import React, { useEffect, useState } from "react";
import api from "@/lib/api";
import { Trophy } from "lucide-react";

export default function RankingsPage() {
	const [managers, setManagers] = useState([]);
	const [products, setProducts] = useState([]);
	const [regions, setRegions] = useState([]);
	const [loading, setLoading] = useState(true);

	useEffect(() => {
		const fetchData = async () => {
			try {
				const [m, p, r] = await Promise.all([
					api.get("/rankings/manager"),
					api.get("/rankings/product"),
					api.get("/rankings/region"),
				]);
				setManagers(m.data);
				setProducts(p.data);
				setRegions(r.data);
			} catch (e) {
				console.error(e);
			} finally {
				setLoading(false);
			}
		};
		fetchData();
	}, []);

	if (loading) return <div>Loading...</div>;

	return (
		<div className="space-y-8">
			<h1 className="text-3xl font-bold text-gray-800">Rankings</h1>

			<div className="grid grid-cols-1 md:grid-cols-3 gap-6">
				<RankingCard
					title="Top Managers"
					data={managers}
					icon={Trophy}
					color="text-yellow-500"
				/>
				<RankingCard
					title="Top Products"
					data={products}
					icon={Trophy}
					color="text-blue-500"
				/>
				<RankingCard
					title="Top Regions"
					data={regions}
					icon={Trophy}
					color="text-purple-500"
				/>
			</div>
		</div>
	);
}

const RankingCard = ({ title, data, icon: Icon, color }: any) => (
	<div className="bg-white rounded-lg shadow overflow-hidden">
		<div className="p-4 border-b flex items-center">
			<Icon className={`w-5 h-5 mr-2 ${color}`} />
			<h2 className="text-lg font-semibold">{title}</h2>
		</div>
		<div className="p-4">
			<ul className="space-y-3">
				{data.map((item: any) => (
					<li key={item.name} className="flex justify-between items-center">
						<div className="flex items-center">
							<span
								className={`w-6 h-6 rounded-full bg-gray-100 flex items-center justify-center text-xs font-bold mr-3 ${item.rank === 1 ? "bg-yellow-100 text-yellow-700" : ""}`}
							>
								{item.rank}
							</span>
							<span className="text-sm font-medium text-gray-700 truncate max-w-[150px]">
								{item.name}
							</span>
						</div>
						<span className="text-sm font-bold text-gray-900">
							${item.revenue.toLocaleString()}
						</span>
					</li>
				))}
			</ul>
		</div>
	</div>
);

"use client";

import React, { useEffect, useState, useCallback } from "react";
import { useParams } from "next/navigation";
import api from "@/lib/api";
import {
	LineChartComponent,
	BarChartComponent,
	PieChartComponent,
} from "@/components/Charts";
import { Filter, RotateCcw } from "lucide-react";

interface DimItem {
	id: number;
	name: string;
}

const REPORTS_CONFIG: any = {
	"region-period-category": {
		title: "Region × Period × Category",
		dim1: "region",
		dim2: "month",
		chartType: "line",
		desc: "Sales performance by region over time.",
	},
	"manager-month-region": {
		title: "Manager × Month × Region",
		dim1: "manager",
		dim2: "month",
		chartType: "bar",
		desc: "Manager performance analysis.",
	},
	"category-quarter-supplier": {
		title: "Category × Quarter × Supplier",
		dim1: "category",
		dim2: "quarter",
		chartType: "bar",
		desc: "Category trends by quarter.",
	},
	"product-region-month": {
		title: "Product × Region × Month",
		dim1: "product",
		dim2: "region",
		chartType: "line",
		desc: "Product distribution across regions.",
	},
	"supplier-category-year": {
		title: "Supplier × Category × Year",
		dim1: "supplier",
		dim2: "category",
		chartType: "pie",
		desc: "Supplier category breakdown.",
	},
};

export default function ReportPage() {
	const params = useParams();
	const slug = params.slug as string;
	const config = REPORTS_CONFIG[slug];

	const [data, setData] = useState([]);
	const [loading, setLoading] = useState(true);
	const [filtersOpen, setFiltersOpen] = useState(false);

	// Dims for dropdowns
	const [dims, setDims] = useState<{
		regions: DimItem[];
		managers: DimItem[];
		suppliers: DimItem[];
		products: DimItem[];
		categories: string[];
	}>({
		regions: [],
		managers: [],
		suppliers: [],
		products: [],
		categories: [
			"Accessories",
			"Cameras",
			"Gaming",
			"Headphones",
			"Home Appliances",
			"Kitchen",
			"Laptops",
			"Monitors",
			"Networking",
			"Printers",
			"Smartphones",
			"Smartwatches",
			"Storage",
			"TV",
			"Wearables",
		],
	});

	// Filter state
	const [filters, setFilters] = useState({
		region: "",
		manager: "",
		category: "",
		supplier: "",
		product: "",
		date_from: "",
		date_to: "",
	});

	useEffect(() => {
		const fetchDims = async () => {
			try {
				const [r, m, s, p] = await Promise.all([
					api.get("/dims/region"),
					api.get("/dims/manager"),
					api.get("/dims/supplier"),
					api.get("/dims/product"),
				]);
				setDims((prev) => ({
					...prev,
					regions: r.data,
					managers: m.data,
					suppliers: s.data,
					products: p.data,
				}));
			} catch (e) {
				console.error(e);
			}
		};
		fetchDims();
	}, []);

	const fetchData = useCallback(async () => {
		if (!config) return;
		setLoading(true);
		try {
			const queryParams: any = {
				dimension1: config.dim1,
				dimension2: config.dim2,
			};

			// Append active filters
			if (filters.region) queryParams.region = filters.region;
			if (filters.manager) queryParams.manager = filters.manager;
			if (filters.category) queryParams.category = filters.category;
			if (filters.supplier) queryParams.supplier = filters.supplier;
			if (filters.product) queryParams.product = filters.product;
			if (filters.date_from) queryParams.date_from = filters.date_from;
			if (filters.date_to) queryParams.date_to = filters.date_to;

			const res = await api.get("/reports/aggregate", {
				params: queryParams,
			});

			const chartData = res.data.map((item: any) => ({
				name: `${item.d1} - ${item.d2}`,
				value: item.value,
				d1: item.d1,
				d2: item.d2,
			}));

			setData(chartData);
		} catch (e) {
			console.error(e);
		} finally {
			setLoading(false);
		}
	}, [slug, filters]);

	useEffect(() => {
		fetchData();
	}, [fetchData]);

	const resetFilters = () => {
		setFilters({
			region: "",
			manager: "",
			category: "",
			supplier: "",
			product: "",
			date_from: "",
			date_to: "",
		});
	};

	const activeFilterCount = Object.values(filters).filter(Boolean).length;

	if (!config) return <div>Report not found</div>;

	return (
		<div className="space-y-6">
			<div className="flex justify-between items-start">
				<div>
					<h1 className="text-2xl font-bold text-gray-800">{config.title}</h1>
					<p className="text-gray-600">{config.desc}</p>
				</div>
				<div className="flex gap-2">
					{activeFilterCount > 0 && (
						<button
							onClick={resetFilters}
							className="flex items-center px-3 py-2 text-sm border rounded-lg text-gray-600 hover:bg-gray-50"
						>
							<RotateCcw className="w-4 h-4 mr-1" />
							Reset
						</button>
					)}
					<button
						onClick={() => setFiltersOpen(!filtersOpen)}
						className={`flex items-center px-4 py-2 text-sm rounded-lg border ${
							filtersOpen || activeFilterCount > 0
								? "bg-indigo-50 border-indigo-300 text-indigo-700"
								: "bg-white text-gray-600 hover:bg-gray-50"
						}`}
					>
						<Filter className="w-4 h-4 mr-2" />
						Filters
						{activeFilterCount > 0 && (
							<span className="ml-2 bg-indigo-600 text-white text-xs rounded-full px-2 py-0.5">
								{activeFilterCount}
							</span>
						)}
					</button>
				</div>
			</div>

			{/* Filters panel */}
			{filtersOpen && (
				<div className="bg-white p-4 rounded-lg shadow border border-gray-200">
					<div className="grid grid-cols-2 md:grid-cols-4 lg:grid-cols-7 gap-3">
						{/* Region */}
						<div>
							<label className="block text-xs font-medium text-gray-500 mb-1">
								Region
							</label>
							<select
								value={filters.region}
								onChange={(e) =>
									setFilters((f) => ({ ...f, region: e.target.value }))
								}
								className="w-full border rounded p-1.5 text-sm"
							>
								<option value="">All</option>
								{dims.regions.map((r) => (
									<option key={r.id} value={r.name.split(" - ")[0]}>
										{r.name}
									</option>
								))}
							</select>
						</div>

						{/* Manager */}
						<div>
							<label className="block text-xs font-medium text-gray-500 mb-1">
								Manager
							</label>
							<select
								value={filters.manager}
								onChange={(e) =>
									setFilters((f) => ({ ...f, manager: e.target.value }))
								}
								className="w-full border rounded p-1.5 text-sm"
							>
								<option value="">All</option>
								{dims.managers.map((m) => (
									<option key={m.id} value={m.name}>
										{m.name}
									</option>
								))}
							</select>
						</div>

						{/* Category */}
						<div>
							<label className="block text-xs font-medium text-gray-500 mb-1">
								Category
							</label>
							<select
								value={filters.category}
								onChange={(e) =>
									setFilters((f) => ({ ...f, category: e.target.value }))
								}
								className="w-full border rounded p-1.5 text-sm"
							>
								<option value="">All</option>
								{dims.categories.map((c) => (
									<option key={c} value={c}>
										{c}
									</option>
								))}
							</select>
						</div>

						{/* Supplier */}
						<div>
							<label className="block text-xs font-medium text-gray-500 mb-1">
								Supplier
							</label>
							<select
								value={filters.supplier}
								onChange={(e) =>
									setFilters((f) => ({ ...f, supplier: e.target.value }))
								}
								className="w-full border rounded p-1.5 text-sm"
							>
								<option value="">All</option>
								{dims.suppliers.map((s) => (
									<option key={s.id} value={s.name}>
										{s.name}
									</option>
								))}
							</select>
						</div>

						{/* Product */}
						<div>
							<label className="block text-xs font-medium text-gray-500 mb-1">
								Product
							</label>
							<select
								value={filters.product}
								onChange={(e) =>
									setFilters((f) => ({ ...f, product: e.target.value }))
								}
								className="w-full border rounded p-1.5 text-sm"
							>
								<option value="">All</option>
								{dims.products.map((p) => (
									<option key={p.id} value={p.name}>
										{p.name}
									</option>
								))}
							</select>
						</div>

						{/* Date From */}
						<div>
							<label className="block text-xs font-medium text-gray-500 mb-1">
								Date From
							</label>
							<input
								type="date"
								value={filters.date_from}
								onChange={(e) =>
									setFilters((f) => ({ ...f, date_from: e.target.value }))
								}
								className="w-full border rounded p-1.5 text-sm"
							/>
						</div>

						{/* Date To */}
						<div>
							<label className="block text-xs font-medium text-gray-500 mb-1">
								Date To
							</label>
							<input
								type="date"
								value={filters.date_to}
								onChange={(e) =>
									setFilters((f) => ({ ...f, date_to: e.target.value }))
								}
								className="w-full border rounded p-1.5 text-sm"
							/>
						</div>
					</div>
				</div>
			)}

			{loading ? (
				<div className="text-center py-12 text-gray-400">
					Loading report data...
				</div>
			) : (
				<div className="grid grid-cols-1 lg:grid-cols-2 gap-6">
					<div className="bg-white p-6 rounded-lg shadow">
						<h3 className="font-semibold mb-4">Trend (Line)</h3>
						<LineChartComponent data={data} xKey="name" yKey="value" />
					</div>
					<div className="bg-white p-6 rounded-lg shadow">
						<h3 className="font-semibold mb-4">Comparison (Bar)</h3>
						<BarChartComponent data={data} xKey="name" yKey="value" />
					</div>
					<div className="bg-white p-6 rounded-lg shadow">
						<h3 className="font-semibold mb-4">Structure (Pie)</h3>
						<PieChartComponent data={data} nameKey="name" valueKey="value" />
					</div>
					<div className="bg-white p-6 rounded-lg shadow max-h-96 overflow-y-auto">
						<h3 className="font-semibold mb-4">Data Table</h3>
						<table className="min-w-full divide-y divide-gray-200">
							<thead>
								<tr>
									<th className="px-4 py-2 text-left text-xs font-medium text-gray-500 uppercase">
										{config.dim1}
									</th>
									<th className="px-4 py-2 text-left text-xs font-medium text-gray-500 uppercase">
										{config.dim2}
									</th>
									<th className="px-4 py-2 text-right text-xs font-medium text-gray-500 uppercase">
										Value
									</th>
								</tr>
							</thead>
							<tbody>
								{data.map((row: any, idx: number) => (
									<tr key={idx}>
										<td className="px-4 py-2 text-sm text-gray-900">
											{row.d1}
										</td>
										<td className="px-4 py-2 text-sm text-gray-500">
											{row.d2}
										</td>
										<td className="px-4 py-2 text-sm text-gray-900 text-right">
											${row.value.toLocaleString()}
										</td>
									</tr>
								))}
							</tbody>
						</table>
					</div>
				</div>
			)}
		</div>
	);
}

"use client";

import React, { useState, useEffect } from "react";
import { useForm } from "react-hook-form";
import api from "@/lib/api";
import { Plus, Edit, Trash2, X, Search } from "lucide-react";

interface Sale {
	id: number;
	sale_id: number;
	date: string;
	product_id: number;
	manager_id: number;
	region_id: number;
	quantity: number;
	unit_price: number;
	discount: number;
	revenue: number;
	payment_type: string;
	sales_channel: string;
	supplier_id: number;
}

export default function SalesPage() {
	const [sales, setSales] = useState<Sale[]>([]);
	const [dims, setDims] = useState<any>({
		products: [],
		managers: [],
		regions: [],
		suppliers: [],
	});
	const [loading, setLoading] = useState(true);
	const [modalOpen, setModalOpen] = useState(false);
	const [editingSale, setEditingSale] = useState<Sale | null>(null);
	const [page, setPage] = useState(1);
	const [totalPages, setTotalPages] = useState(1);
	const [searchTerm, setSearchTerm] = useState("");
	const [searchInput, setSearchInput] = useState("");
	const pageSize = 10;

	const { register, handleSubmit, reset, setValue } = useForm();

	const fetchSales = async () => {
		setLoading(true);
		try {
			const skip = (page - 1) * pageSize;
			const params: any = { skip, limit: pageSize };
			if (searchTerm) params.search = searchTerm;

			const [res, countRes] = await Promise.all([
				api.get("/sales", { params }),
				api.get("/sales/count", {
					params: searchTerm ? { search: searchTerm } : {},
				}),
			]);
			setSales(res.data);
			setTotalPages(Math.max(1, Math.ceil(countRes.data.count / pageSize)));
		} catch (e) {
			console.error(e);
		} finally {
			setLoading(false);
		}
	};

	const fetchDims = async () => {
		try {
			const [p, m, r, s] = await Promise.all([
				api.get("/dims/product"),
				api.get("/dims/manager"),
				api.get("/dims/region"),
				api.get("/dims/supplier"),
			]);
			setDims({
				products: p.data,
				managers: m.data,
				regions: r.data,
				suppliers: s.data,
			});
		} catch (e) {
			console.error(e);
		}
	};

	useEffect(() => {
		fetchSales();
	}, [page, searchTerm]);

	useEffect(() => {
		fetchDims();
	}, []);

	const onSubmit = async (data: any) => {
		try {
			const payload = {
				...data,
				date: data.date,
				quantity: parseInt(data.quantity),
				unit_price: parseFloat(data.unit_price),
				discount: parseFloat(data.discount),
				product_id: parseInt(data.product_id),
				manager_id: parseInt(data.manager_id),
				region_id: parseInt(data.region_id),
				supplier_id: parseInt(data.supplier_id),
			};

			if (editingSale) {
				await api.put(`/sales/${editingSale.id}`, payload);
			} else {
				await api.post("/sales", payload);
			}
			setModalOpen(false);
			reset();
			setEditingSale(null);
			fetchSales();
		} catch (e) {
			console.error("Failed to save sale", e);
			alert("Failed to save. Check console.");
		}
	};

	const handleDelete = async (id: number) => {
		if (!confirm("Are you sure?")) return;
		try {
			await api.delete(`/sales/${id}`);
			fetchSales();
		} catch (e) {
			console.error(e);
		}
	};

	const openEdit = (sale: Sale) => {
		setEditingSale(sale);
		setValue("date", sale.date);
		setValue("product_id", sale.product_id);
		setValue("manager_id", sale.manager_id);
		setValue("region_id", sale.region_id);
		setValue("supplier_id", sale.supplier_id);
		setValue("quantity", sale.quantity);
		setValue("unit_price", sale.unit_price);
		setValue("discount", sale.discount);
		setValue("payment_type", sale.payment_type);
		setValue("sales_channel", sale.sales_channel);
		setModalOpen(true);
	};

	const openAdd = () => {
		setEditingSale(null);
		reset();
		setModalOpen(true);
	};

	if (loading) return <div>Loading...</div>;

	return (
		<div>
			<div className="flex justify-between items-center mb-4">
				<h1 className="text-3xl font-bold text-gray-800">Sales Management</h1>
				{/* <button
					onClick={openAdd}
					className="bg-blue-600 text-white px-4 py-2 rounded flex items-center hover:bg-blue-700"
				>
					<Plus className="w-4 h-4 mr-2" />
					Add Sale
				</button> */}
			</div>

			{/* Search bar */}
			<div className="mb-4 flex gap-2">
				<div className="relative flex-1">
					<Search className="absolute left-3 top-1/2 transform -translate-y-1/2 w-4 h-4 text-gray-400" />
					<input
						type="text"
						placeholder="Search by product, manager, region, or city..."
						value={searchInput}
						onChange={(e) => setSearchInput(e.target.value)}
						onKeyDown={(e) => {
							if (e.key === "Enter") {
								setPage(1);
								setSearchTerm(searchInput);
							}
						}}
						className="w-full pl-10 pr-4 py-2 border rounded-lg text-sm focus:outline-none focus:ring-2 focus:ring-blue-400"
					/>
				</div>
				<button
					onClick={() => {
						setPage(1);
						setSearchTerm(searchInput);
					}}
					className="px-4 py-2 bg-blue-600 text-white rounded-lg text-sm hover:bg-blue-700"
				>
					Search
				</button>
				{searchTerm && (
					<button
						onClick={() => {
							setSearchInput("");
							setSearchTerm("");
							setPage(1);
						}}
						className="px-4 py-2 border rounded-lg text-sm text-gray-600 hover:bg-gray-50"
					>
						Clear
					</button>
				)}
			</div>

			<div className="bg-white rounded-lg shadow overflow-hidden">
				<table className="min-w-full divide-y divide-gray-200">
					<thead className="bg-gray-50">
						<tr>
							<th className="px-6 py-3 text-left text-xs font-medium text-gray-500 uppercase tracking-wider">
								Date
							</th>
							<th className="px-6 py-3 text-left text-xs font-medium text-gray-500 uppercase tracking-wider">
								Product
							</th>
							<th className="px-6 py-3 text-left text-xs font-medium text-gray-500 uppercase tracking-wider">
								Manager
							</th>
							<th className="px-6 py-3 text-left text-xs font-medium text-gray-500 uppercase tracking-wider">
								Qty
							</th>
							<th className="px-6 py-3 text-left text-xs font-medium text-gray-500 uppercase tracking-wider">
								Revenue
							</th>
							<th className="px-6 py-3 text-right text-xs font-medium text-gray-500 uppercase tracking-wider">
								Actions
							</th>
						</tr>
					</thead>
					<tbody className="bg-white divide-y divide-gray-200">
						{sales.map((sale) => (
							<tr key={sale.id}>
								<td className="px-6 py-4 whitespace-nowrap text-sm text-gray-500">
									{sale.date}
								</td>
								<td className="px-6 py-4 whitespace-nowrap text-sm text-gray-900">
									{dims.products.find((p: any) => p.id === sale.product_id)
										?.name || sale.product_id}
								</td>
								<td className="px-6 py-4 whitespace-nowrap text-sm text-gray-500">
									{dims.managers.find((m: any) => m.id === sale.manager_id)
										?.name || sale.manager_id}
								</td>
								<td className="px-6 py-4 whitespace-nowrap text-sm text-gray-500">
									{sale.quantity}
								</td>
								<td className="px-6 py-4 whitespace-nowrap text-sm text-gray-500">
									${sale.revenue}
								</td>
								<td className="px-6 py-4 whitespace-nowrap text-right text-sm font-medium">
									{/* <button
										onClick={() => openEdit(sale)}
										className="text-indigo-600 hover:text-indigo-900 mr-4"
									>
										<Edit className="w-4 h-4" />
									</button> */}
									<button
										onClick={() => handleDelete(sale.id)}
										className="text-red-600 hover:text-red-900"
									>
										<Trash2 className="w-4 h-4" />
									</button>
								</td>
							</tr>
						))}
					</tbody>
				</table>
			</div>

			{/* Pagination Controls */}
			<div className="mt-4 flex justify-between items-center">
				<button
					disabled={page === 1}
					onClick={() => setPage((p) => Math.max(1, p - 1))}
					className={`px-4 py-2 border rounded ${page === 1 ? "bg-gray-100 text-gray-400" : "bg-white hover:bg-gray-50"}`}
				>
					Previous
				</button>
				<span className="text-gray-600">
					Page {page} of {totalPages}
				</span>
				<button
					disabled={page >= totalPages}
					onClick={() => setPage((p) => Math.min(totalPages, p + 1))}
					className={`px-4 py-2 border rounded ${page >= totalPages ? "bg-gray-100 text-gray-400" : "bg-white hover:bg-gray-50"}`}
				>
					Next
				</button>
			</div>

			{modalOpen && (
				<div className="fixed inset-0 bg-black bg-opacity-50 flex items-center justify-center p-4">
					<div className="bg-white rounded-lg p-6 w-full max-w-2xl max-h-[90vh] overflow-y-auto">
						<div className="flex justify-between items-center mb-4">
							<h2 className="text-xl font-bold">
								{editingSale ? "Edit Sale" : "New Sale"}
							</h2>
							<button onClick={() => setModalOpen(false)}>
								<X className="w-6 h-6 border rounded" />
							</button>
						</div>

						<form onSubmit={handleSubmit(onSubmit)} className="space-y-4">
							<div className="grid grid-cols-2 gap-4">
								<div>
									<label className="block text-sm font-medium text-gray-700">
										Date
									</label>
									<input
										type="date"
										{...register("date")}
										required
										className="mt-1 block w-full border rounded p-2"
									/>
								</div>
								<div>
									<label className="block text-sm font-medium text-gray-700">
										Product
									</label>
									<select
										{...register("product_id")}
										required
										className="mt-1 block w-full border rounded p-2"
									>
										<option value="">Select Product...</option>
										{dims.products.map((p: any) => (
											<option key={p.id} value={p.id}>
												{p.name}
											</option>
										))}
									</select>
								</div>
								<div>
									<label className="block text-sm font-medium text-gray-700">
										Manager
									</label>
									<select
										{...register("manager_id")}
										required
										className="mt-1 block w-full border rounded p-2"
									>
										<option value="">Select Manager...</option>
										{dims.managers.map((m: any) => (
											<option key={m.id} value={m.id}>
												{m.name}
											</option>
										))}
									</select>
								</div>
								<div>
									<label className="block text-sm font-medium text-gray-700">
										Region
									</label>
									<select
										{...register("region_id")}
										required
										className="mt-1 block w-full border rounded p-2"
									>
										<option value="">Select Region...</option>
										{dims.regions.map((r: any) => (
											<option key={r.id} value={r.id}>
												{r.name}
											</option>
										))}
									</select>
								</div>
								<div>
									<label className="block text-sm font-medium text-gray-700">
										Supplier
									</label>
									<select
										{...register("supplier_id")}
										required
										className="mt-1 block w-full border rounded p-2"
									>
										<option value="">Select Supplier...</option>
										{dims.suppliers.map((s: any) => (
											<option key={s.id} value={s.id}>
												{s.name}
											</option>
										))}
									</select>
								</div>
								<div>
									<label className="block text-sm font-medium text-gray-700">
										Quantity
									</label>
									<input
										type="number"
										{...register("quantity")}
										required
										className="mt-1 block w-full border rounded p-2"
									/>
								</div>
								<div>
									<label className="block text-sm font-medium text-gray-700">
										Unit Price
									</label>
									<input
										type="number"
										step="0.01"
										{...register("unit_price")}
										required
										className="mt-1 block w-full border rounded p-2"
									/>
								</div>
								<div>
									<label className="block text-sm font-medium text-gray-700">
										Discount
									</label>
									<input
										type="number"
										step="0.01"
										{...register("discount")}
										defaultValue={0}
										className="mt-1 block w-full border rounded p-2"
									/>
								</div>
								<div>
									<label className="block text-sm font-medium text-gray-700">
										Payment
									</label>
									<select
										{...register("payment_type")}
										className="mt-1 block w-full border rounded p-2"
									>
										<option value="cash">Cash</option>
										<option value="card">Card</option>
										<option value="online">Online</option>
										<option value="invoice">Invoice</option>
									</select>
								</div>
								<div>
									<label className="block text-sm font-medium text-gray-700">
										Channel
									</label>
									<select
										{...register("sales_channel")}
										className="mt-1 block w-full border rounded p-2"
									>
										<option value="store">Store</option>
										<option value="online_store">Online Store</option>
										<option value="marketplace">Marketplace</option>
										<option value="wholesale">Wholesale</option>
										<option value="phone_order">Phone Order</option>
									</select>
								</div>
							</div>

							<div className="flex justify-end pt-4">
								<button
									type="button"
									onClick={() => setModalOpen(false)}
									className="mr-2 px-4 py-2 border rounded text-gray-600"
								>
									Cancel
								</button>
								<button
									type="submit"
									className="px-4 py-2 bg-blue-600 text-white rounded hover:bg-blue-700"
								>
									Save
								</button>
							</div>
						</form>
					</div>
				</div>
			)}
		</div>
	);
}

"use client";

import React, { useState } from "react";
import api from "@/lib/api";
import {
	Upload,
	FileSpreadsheet,
	CheckCircle,
	AlertCircle,
} from "lucide-react";

export default function UploadPage() {
	const [file, setFile] = useState<File | null>(null);
	const [uploading, setUploading] = useState(false);
	const [status, setStatus] = useState<{
		type: "success" | "error" | null;
		message: string;
	}>({ type: null, message: "" });

	const handleFileChange = (e: React.ChangeEvent<HTMLInputElement>) => {
		if (e.target.files && e.target.files[0]) {
			setFile(e.target.files[0]);
			setStatus({ type: null, message: "" });
		}
	};

	const handleUpload = async () => {
		if (!file) return;

		setUploading(true);
		setStatus({ type: null, message: "" });

		const formData = new FormData();
		formData.append("file", file);

		try {
			const res = await api.post("/upload/sales", formData, {
				headers: {
					"Content-Type": "multipart/form-data",
				},
			});
			setStatus({
				type: "success",
				message: `Successfully processed ${res.data.rows_inserted} new records (from ${res.data.rows_processed} total).`,
			});
			setFile(null);
		} catch (e: any) {
			console.error(e);
			setStatus({
				type: "error",
				message:
					e.response?.data?.detail ||
					"Failed to upload file. Please check format.",
			});
		} finally {
			setUploading(false);
		}
	};

	return (
		<div className="max-w-2xl mx-auto">
			<h1 className="text-3xl font-bold text-gray-800 mb-6">
				Upload Sales Data
			</h1>

			<div className="bg-white rounded-lg shadow-md p-8">
				<div className="border-2 border-dashed border-gray-300 rounded-lg p-12 text-center hover:bg-gray-50 transition-colors">
					<div className="flex flex-col items-center">
						<FileSpreadsheet className="w-16 h-16 text-green-600 mb-4" />
						<p className="text-gray-600 mb-2">
							Select an Excel file (.xlsx) containing sales data.
						</p>
						<input
							type="file"
							accept=".xlsx, .xls"
							onChange={handleFileChange}
							className="block w-full text-sm text-gray-500
                                file:mr-4 file:py-2 file:px-4
                                file:rounded-full file:border-0
                                file:text-sm file:font-semibold
                                file:bg-blue-50 file:text-blue-700
                                hover:file:bg-blue-100
                                mt-4
                            "
						/>
					</div>
				</div>

				{file && (
					<div className="mt-6 flex items-center justify-between bg-gray-50 p-4 rounded">
						<div className="flex items-center">
							<FileSpreadsheet className="w-5 h-5 text-gray-500 mr-2" />
							<span className="text-gray-700 font-medium">{file.name}</span>
							<span className="text-gray-400 text-sm ml-2">
								({(file.size / 1024).toFixed(1)} KB)
							</span>
						</div>
						<button
							onClick={handleUpload}
							disabled={uploading}
							className={`px-4 py-2 rounded flex items-center ${
								uploading
									? "bg-gray-400 cursor-not-allowed"
									: "bg-blue-600 hover:bg-blue-700 text-white"
							}`}
						>
							{uploading ? (
								<>Loading...</>
							) : (
								<>
									<Upload className="w-4 h-4 mr-2" />
									Upload
								</>
							)}
						</button>
					</div>
				)}

				{status.type && (
					<div
						className={`mt-6 p-4 rounded flex items-start ${
							status.type === "success"
								? "bg-green-50 text-green-800"
								: "bg-red-50 text-red-800"
						}`}
					>
						{status.type === "success" ? (
							<CheckCircle className="w-5 h-5 mr-2 mt-0.5 flex-shrink-0" />
						) : (
							<AlertCircle className="w-5 h-5 mr-2 mt-0.5 flex-shrink-0" />
						)}
						<div>
							<h3 className="font-bold">
								{status.type === "success" ? "Success" : "Error"}
							</h3>
							<p className="text-sm">{status.message}</p>
						</div>
					</div>
				)}
			</div>

			<div className="mt-8">
				<h3 className="text-lg font-semibold mb-2">Expected Columns</h3>
				<ul className="list-disc list-inside text-gray-600 space-y-1">
					<li>
						<code>sale_id</code> (Unique ID)
					</li>
					<li>
						<code>sale_datetime</code> (Date/Time)
					</li>
					<li>
						<code>region_name</code>, <code>city</code>
					</li>
					<li>
						<code>manager</code>
					</li>
					<li>
						<code>product_id</code>, <code>product_name</code>,{" "}
						<code>brand</code>, <code>category</code>
					</li>
					<li>
						<code>supplier_name</code>, <code>supplier_country</code>
					</li>
					<li>
						<code>quantity</code>, <code>unit_price</code>,{" "}
						<code>discount</code>
					</li>
					<li>
						<code>payment_type</code>, <code>sales_channel</code>
					</li>
				</ul>
			</div>
		</div>
	);
}
